# Program: transform_code.rb
#
# Purpose: Read an Inform 6 dictionary file, previously generated by 
# build_dictionary.rb, then read any number of Inform 6 source code files,
# creating a new version of each, where all dictionary words have been changed
# to the corresponding constants from the dictionary file.
#
# Note: Dictionary words that contain a space are not considered.
#
# E.g. "ruby transform_code.rb dict.inf source1.inf source2.inf"
# This creates two new files (overwriting them if they already exist!), called
# generated_source1.inf and generated_source2.inf

if ARGV.length < 2
	puts "Sample usage: ruby transform_code.rb dictionary.inf mygame.inf parser.inf ..."
	puts "Note: This CREATES/OVERWRITES generated_mygame.inf and generated_parser.inf"
	exit 1
end

$dictionary_file = ARGV[0]
$words = {}

#######################################
# Read dictionary
#######################################

File.open($dictionary_file).each_line do |line|
	clean = line.chomp.strip
	if clean =~ /^Constant (W_[A-Z0-9_]+)\s*=\s*-?\d+\s*;\s*!\s*(.*)$/
		const = $1
		source_word = $2.strip
		source_word = $1 if source_word =~ /^[^|]+\|([^\s]+)\s*$/
		if $words.has_key? source_word
			puts "ERROR: #{source_word} occurs multiple times in #{$dictionary_file}"
			exit 1
		end
		$words[source_word] = const
#		puts "#{const}=#{source_word}"
	end		
end

#######################################
# Create/update generated.inf
#######################################

1.upto(ARGV.count - 1) do |argno|
	source_file = ARGV[argno]
	target_file = "generated_" + source_file

	if source_file =~ /^generated/i 
		puts "ERROR: A source file name (#{source_file}) starts with 'generated', this is illegal!"
		exit 1
	end

	linenum = 0

	File.open(target_file, 'w') do |file|
		File.open(source_file).each_line do |line|
			linenum += 1
			if line =~ /'[^ ']{2,}'/
				ix = 0
				done = false
				while done == false and 
						m = line.match(/'([^ ']{2,20})'(?:\s*=\s*W_([A-Z0-9_]+))?/, ix)
					source_word = m[1]
					source_word_downcased = m[1].downcase
					if m[2]
						# This line is a constant name definition, (e.g. "! 'me' = W_MEWORD")
						done = true
					else
						# Replace with constant
						full_source_word = "'#{source_word}'"
						unless $words.has_key? source_word_downcased
							puts "ERROR [#{linenum}]: #{source_word_downcased} " + 
									"is missing in #{$dictionary_file}"
							exit 1
						end
						const = $words[source_word_downcased]
						line2 = line.gsub(full_source_word, const)
						if line2 == line
							puts "ERROR [#{linenum}]: Failed to replace #{source_word} " + 
									" with constant #{const}"
							exit 1
						end
						line = line2
	#	#				puts "source_word: #{source_word} zscii_word: #{zscii_word}"
	#				ix = m.end(0) + 1
					end
				end
			end
			file.puts line
		end
	end
end
